allow:
Bash(powershell -Command "
\\$pids = \(Get-NetTCPConnection -LocalPort 5000 -ErrorAction SilentlyContinue\).OwningProcess
if \(\\$pids\) {
  \\$pids | ForEach-Object { Stop-Process -Id \\$_ -Force -ErrorAction SilentlyContinue }
  Write-Host 'Killed PIDs:' \(\\$pids -join ', '\)
} else {
  Write-Host 'No process on port 5000'
}
" 2>&1)
